import Foundation

enum HisnulMuslimData {
    static let entries: [RehberEntry] = [
        RehberEntry(id: "hisnul_sabah_01", title: "Sabah Azkarı — Ayetel Kürsi", arabicText: "اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ", transliteration: "Allâhu lâ ilâhe illâ Hüvel-Hayyül-Kayyûm", meaning: "Allah, kendisinden başka hiçbir ilah olmayandır; O, daima diridir, her şeyi ayakta tutandır.", purpose: "Sabah 1 defa okuyan akşama kadar cinlerden, insanlardan ve her türlü kötülükten korunur. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Sabah", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_sabah_02", title: "Sabah Azkarı — Üç İhlas & Muavvizeteyn", arabicText: "قُلْ هُوَ اللَّهُ أَحَدٌ • قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ • قُلْ أَعُوذُ بِرَبِّ النَّاسِ", transliteration: "Kul huvallâhu ehad, kul eûzu birabbil felak, kul eûzu birabbin nâs", meaning: "İhlas, Felak ve Nas surelerinin okunması.", purpose: "Her biri 3 defa okunursa her şeye karşı yeterli olur. (Hadis: Ebû Dâvûd)", recommendedCount: 3, category: .hisnulMuslim, notes: "Her sureyi 3 defa", schedule: "Sabah & Akşam", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_sabah_03", title: "Sabah Azkarı — Seyyidü'l İstiğfar", arabicText: "اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ", transliteration: "Allâhümme ente rabbî lâ ilâhe illâ ente halaktenî ve ene abdüke ve ene alâ ahdike ve va'dike mestetatu", meaning: "Allah'ım Sen benim Rabbimsin. Senden başka ilah yoktur. Sen beni yarattın. Ben Senin kulunum.", purpose: "Sabah okuyan ve aynı gün akşama çıkmadan ölürse cennete girer. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Sabah", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_sabah_04", title: "Sabah Azkarı — Eûzü Kelimât", arabicText: "أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ", transliteration: "Eûzü bi-kelimâtillâhit-tâmmâti min şerri mâ halak", meaning: "Yarattığı şeylerin şerrinden Allah'ın eksiksiz kelimeleriyle sığınırım.", purpose: "Akşam 3 defa okuyan, o gece hiçbir zehirden zarar görmez. (Hadis: Müslim)", recommendedCount: 3, category: .hisnulMuslim, schedule: "Akşam", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_sabah_05", title: "Sabah Azkarı — Bismillah Korunma", arabicText: "بِسْمِ اللَّهِ الَّذِي لَا يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الْأَرْضِ وَلَا فِي السَّمَاءِ", transliteration: "Bismillâhillezî lâ yedurru mea'smihî şey'ün fil-ardi ve lâ fis-semâ'i ve hüves-semîul-alîm", meaning: "O'nun adıyla beraber yerde ve gökte hiçbir şey zarar veremez. O, işitir ve bilir.", purpose: "Sabah-akşam 3 defa okuyanı hiçbir musibet ve ani bela çarpmaz. (Hadis: Tirmizî)", recommendedCount: 3, category: .hisnulMuslim, schedule: "Sabah & Akşam", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_sabah_06", title: "Sabah Azkarı — Rıza Duası", arabicText: "رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا", transliteration: "Radîtü billâhi rabben ve bil-islâmi dînen ve bi-Muhammedin nebiyyâ", meaning: "Allah'ı Rab, İslam'ı din, Muhammed'i (s.a.v.) peygamber olarak kabul ettim.", purpose: "Sabah ve akşam 3 defa okuyanın cennete girmeyi hak etmesi Allah üzerine borç olur. (Hadis: Ebû Dâvûd)", recommendedCount: 3, category: .hisnulMuslim, schedule: "Sabah & Akşam", moodTags: ["sukur"]),
        RehberEntry(id: "hisnul_sabah_07", title: "Sabah Azkarı — Sübhanallah 100", arabicText: "سُبْحَانَ اللَّهِ وَبِحَمْدِهِ", transliteration: "Sübhânallâhi ve bihamdih", meaning: "Allah'ı hamdiyle tesbih ederim.", purpose: "Sabah 100 defa okuyan, kıyamete kadar hiç kimse ondan daha fazla sevap getiremez. (Hadis: Müslim)", recommendedCount: 100, category: .hisnulMuslim, schedule: "Sabah", moodTags: ["sukur"]),
        RehberEntry(id: "hisnul_aksam_01", title: "Akşam Azkarı — Hasbiyal Kelimesi", arabicText: "حَسْبِيَ اللَّهُ لَا إِلَهَ إِلَّا هُوَ عَلَيْهِ تَوَكَّلْتُ وَهُوَ رَبُّ الْعَرْشِ الْعَظِيمِ", transliteration: "Hasbiyallâhü lâ ilâhe illâ Hüve aleyhi tevekkeltü ve Hüve Rabbül-arşil-azîm", meaning: "Allah bana yeter. O'ndan başka ilah yoktur. O'na dayandım. O büyük arşın Rabbidir.", purpose: "Sabah-akşam 7 defa okuyanın dünya ve ahiret işleri için Allah yeter. (Hadis: Ebû Dâvûd)", recommendedCount: 7, category: .hisnulMuslim, schedule: "Sabah & Akşam", moodTags: ["huzursuz", "darda_kaldim"]),
        RehberEntry(id: "hisnul_yemek_01", title: "Yemek Öncesi Dua", arabicText: "بِسْمِ اللَّهِ", transliteration: "Bismillâh", meaning: "Allah'ın adıyla.", purpose: "Yemeğe başlarken söylenir. Söylemeden başlarsa hatırladığında ekler: Bismillâhi evvelehû ve âhirehû.", recommendedCount: 1, category: .hisnulMuslim, schedule: "Yemekten önce"),
        RehberEntry(id: "hisnul_yemek_02", title: "Yemek Sonrası Dua", arabicText: "الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنِي هَذَا وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ", transliteration: "Elhamdülillâhillezî at'amenî hâzâ ve razakanîhi min ğayri havlin minnî ve lâ kuvvetin", meaning: "Bana bunu yediren ve benden hiçbir güç ve kuvvet olmaksızın rızıklandıran Allah'a hamd olsun.", purpose: "Yemekten sonra söylenir. Geçmiş günahları bağışlanır. (Hadis: Tirmizî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Yemekten sonra", moodTags: ["sukur"]),
        RehberEntry(id: "hisnul_eve_girmek", title: "Eve Girerken Dua", arabicText: "بِسْمِ اللَّهِ وَلَجْنَا وَبِسْمِ اللَّهِ خَرَجْنَا وَعَلَى اللَّهِ رَبِّنَا تَوَكَّلْنَا", transliteration: "Bismillâhi velecnâ ve bismillâhi harecnâ ve alâllâhi rabbinâ tevekkelnâ", meaning: "Allah'ın adıyla girdik, Allah'ın adıyla çıktık ve Rabbimiz Allah'a tevekkül ettik.", purpose: "Eve girerken söylenir. Şeytan: 'Burada geceleme yeriniz ve akşam yemeğiniz yok' der ve çıkar. (Hadis: Ebû Dâvûd)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Eve girerken"),
        RehberEntry(id: "hisnul_evden_cikarken", title: "Evden Çıkarken Dua", arabicText: "بِسْمِ اللَّهِ تَوَكَّلْتُ عَلَى اللَّهِ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ", transliteration: "Bismillâhi tevekkeltü alâllâhi lâ havle ve lâ kuvvete illâ billâh", meaning: "Allah'ın adıyla, Allah'a dayandım. Güç ve kuvvet yalnız Allah'tandır.", purpose: "Evden çıkarken okunur. Bir melek 'İhtiyacın giderildi, korudun ve yönlendirildim' der. (Hadis: Tirmizî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Evden çıkarken", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_camiye_girmek", title: "Camiye Girerken Dua", arabicText: "اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ", transliteration: "Allâhümme'ftah lî ebvâbe rahmetike", meaning: "Allah'ım, bana rahmetinin kapılarını aç.", purpose: "Camiye sağ ayakla girerken okunur. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Camiye girerken"),
        RehberEntry(id: "hisnul_camiden_cikarken", title: "Camiden Çıkarken Dua", arabicText: "اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ", transliteration: "Allâhümme innî es'elüke min fadlik", meaning: "Allah'ım, Senden fazlından istiyorum.", purpose: "Camiden sol ayakla çıkarken okunur. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Camiden çıkarken"),
        RehberEntry(id: "hisnul_ezan_duasi", title: "Ezan Duası (Sonrası)", arabicText: "اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ وَالصَّلَاةِ الْقَائِمَةِ آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ", transliteration: "Allâhümme rabbe hâzihi'd-da'vetit-tâmmeti ve's-salâtil-kâimeti âti Muhammeden el-vesîlete vel-fadîlete", meaning: "Allah'ım, bu tam ve eksiksiz çağrının ve kılınacak namazın Rabbi! Muhammed'e vesileyi ve fazileti ver.", purpose: "Ezan bitiminde okuyanın kıyamet gününde şefaate nail olması umulur. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Ezan sonrası"),
        RehberEntry(id: "hisnul_sabah_uyanis", title: "Uyanırken Dua", arabicText: "الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ", transliteration: "Elhamdülillâhillezî ahyânâ ba'de mâ emâtenâ ve ileyhin-nüşûr", meaning: "Bizi öldürdükten sonra dirilten Allah'a hamd olsun. Dönüş O'nadır.", purpose: "Uykudan kalkarken söylenir.", recommendedCount: 1, category: .hisnulMuslim, schedule: "Sabah uyanınca", moodTags: ["sukur"]),
        RehberEntry(id: "hisnul_uyurken", title: "Uyumadan Önce Dua", arabicText: "بِاسْمِكَ اللَّهُمَّ أَمُوتُ وَأَحْيَا", transliteration: "Bismikellâhümme emûtü ve ahyâ", meaning: "Allah'ım, Senin adınla ölür ve yaşarım.", purpose: "Uyumadan önce okunur. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Yatmadan önce"),
        RehberEntry(id: "hisnul_sefer_duasi", title: "Yolculuk Duası", arabicText: "اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا", transliteration: "Allâhu ekber, Allâhu ekber, Allâhu ekber. Sübhânellezî sahhara lenâ hâzâ", meaning: "Allah en büyüktür (x3). Bunu bize boyun eğdireni tesbih ederiz.", purpose: "Yolculuğa çıkarken binite binildiğinde okunur. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Yolculukta"),
        RehberEntry(id: "hisnul_hasta_ziyaret", title: "Hasta Ziyaretinde Dua", arabicText: "لَا بَأْسَ طَهُورٌ إِنْ شَاءَ اللَّهُ", transliteration: "Lâ be'se tahûrun inşâallâh", meaning: "Üzülme, inşaallah bir temizliktir.", purpose: "Hasta ziyaretinde hastaya söylenir. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Hasta ziyaretinde"),
        RehberEntry(id: "hisnul_hastaya_dua", title: "Hastaya Okunacak Dua", arabicText: "اللَّهُمَّ رَبَّ النَّاسِ أَذْهِبِ الْبَأْسَ اشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا", transliteration: "Allâhümme rabben-nâsi ezhibil be'se'şfi ente'ş-şâfî lâ şifâ'e illâ şifâuke şifâ'en lâ yüğâdiru sekamen", meaning: "Allah'ım, insanların Rabbi! Hastalığı gider. Şifayı ver. Şifa veren Sensin. Senin şifandan başka şifa yok.", purpose: "Hasta için okunur. 7 defa uygulanır. (Hadis: Buhârî)", recommendedCount: 7, category: .hisnulMuslim, schedule: "İhtiyaç halinde", moodTags: ["hasta_oldum"]),
        RehberEntry(id: "hisnul_agri_rukyesi", title: "Ağrıya Rukye", arabicText: "بِسْمِ اللَّهِ • أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُ وَأُحَاذِرُ", transliteration: "Bismillâh (x3) — Eûzü bi-izzatillâhi ve kudratihî min şerri mâ ecidu ve uhâzir (x7)", meaning: "Allah'ın ismiyle. Allah'ın izzetine ve kudretine sığınırım; hissettiğim ve çekindiğim şeyin şerrinden.", purpose: "Vücutta hissedilen ağrıya okunur. Eliyle o yere 7 defa okunur. (Hadis: Müslim)", recommendedCount: 7, category: .hisnulMuslim, notes: "Bismillah 3, ardından dua 7 defa", schedule: "İhtiyaç halinde", moodTags: ["hasta_oldum"]),
        RehberEntry(id: "hisnul_sıkıntı_duası", title: "Sıkıntı ve Keder Duası", arabicText: "اللَّهُمَّ إِنِّي عَبْدُكَ وَابْنُ عَبْدِكَ وَابْنُ أَمَتِكَ نَاصِيَتِي بِيَدِكَ مَاضٍ فِيَّ حُكْمُكَ عَدْلٌ فِيَّ قَضَاؤُكَ", transliteration: "Allâhümme innî abdüke ve ibni abdike ve ibni emetike nâsıyetî bi-yedike mâdin fiyye hükmüke adlün fiyye kadâuke", meaning: "Allah'ım, Ben Senin kulun, kulunun ve cariyenin oğluyum. Alnım Senin elindedir. Hükmün bende geçerlidir.", purpose: "Sıkıntı, keder ve gamda okunur. Allah sıkıntısını giderir. (Hadis: Ahmed)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Sıkıntı halinde", moodTags: ["huzursuz", "darda_kaldim"]),
        RehberEntry(id: "hisnul_borç_duası", title: "Borç ve Sıkıntı Duası", arabicText: "اللَّهُمَّ اكْفِنِي بِحَلَالِكَ عَنْ حَرَامِكَ وَأَغْنِنِي بِفَضْلِكَ عَمَّنْ سِوَاكَ", transliteration: "Allâhümme'kfinî bi-halâlike an harâmike ve ağninî bi-fadlıke ammen sivâk", meaning: "Allah'ım, helal rızkınla beni haramdan uzak tut ve fazlınla beni senden başkasına muhtaç etme.", purpose: "Dağ gibi borcu olsa Allah öder. (Hadis: Tirmizî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Sabah & Akşam", moodTags: ["darda_kaldim"]),
        RehberEntry(id: "hisnul_abdest_duası", title: "Abdest Bitiminde Dua", arabicText: "أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ", transliteration: "Eşhedü en lâ ilâhe illallâhü vahdehû lâ şerîke lehû ve eşhedü enne Muhammeden abdühû ve rasûlüh", meaning: "Allah'tan başka ilah olmadığına, O'nun bir olduğuna ve ortağı bulunmadığına şehadet ederim.", purpose: "Abdest sonrası okunursa cennetin 8 kapısı açılır. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Abdest sonrası"),
        RehberEntry(id: "hisnul_rüzgar_duası", title: "Rüzgar Eserken Dua", arabicText: "اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَهَا وَخَيْرَ مَا فِيهَا وَخَيْرَ مَا أُرْسِلَتْ بِهِ", transliteration: "Allâhümme innî es'elüke hayraha ve hayra mâ fîhâ ve hayra mâ ürsilet bih", meaning: "Allah'ım, bu rüzgarın hayırlısını ve içindekinin hayırlısını ve onunla gönderilenlerin hayırlısını istiyorum.", purpose: "Kuvvetli rüzgar estiğinde okunur. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "İhtiyaç halinde"),
        RehberEntry(id: "hisnul_şükür_duası", title: "Nimet Şükrü Duası", arabicText: "الْحَمْدُ لِلَّهِ الَّذِي بِنِعْمَتِهِ تَتِمُّ الصَّالِحَاتُ", transliteration: "Elhamdülillâhillezî bi-ni'metihî tetimmüs-sâlihât", meaning: "Nimetleriyle iyiliklerin tamamlandığı Allah'a hamd olsun.", purpose: "Bir nimet geldiğinde ve güzel bir şey görüldüğünde okunur. (Hadis: İbn Mâce)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Nimet anında", moodTags: ["sukur"]),
        RehberEntry(id: "hisnul_musibette", title: "Musibet Anında Dua", arabicText: "إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ اللَّهُمَّ أْجُرْنِي فِي مُصِيبَتِي وَأَخْلِفْ لِي خَيْرًا مِنْهَا", transliteration: "İnnâ lillâhi ve innâ ileyhi râciûn. Allâhümme'cürnî fî musîbetî ve ahlif lî hayran minhâ", meaning: "Şüphesiz biz Allah'a aitiz ve O'na dönücüleriz. Musibetimde bana ecir ver ve daha iyisini nasip et.", purpose: "Bir musibet geldiğinde okunursa Allah daha iyisini verir. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Musibet anında", moodTags: ["darda_kaldim"]),
        RehberEntry(id: "hisnul_dusmanlar", title: "Düşmandan Korunma Duası", arabicText: "اللَّهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ", transliteration: "Allâhümmekfinîhim bi-mâ şi'te", meaning: "Allah'ım, onlara karşı dilediğin şekilde bana yetici ol.", purpose: "Zalim ya da düşmandan korkan kişi okur. (Hadis: Müslim)", recommendedCount: 1, category: .hisnulMuslim, schedule: "İhtiyaç halinde", moodTags: ["darda_kaldim"]),
        RehberEntry(id: "hisnul_sinav_duası", title: "Sınav ve İş Başında Dua", arabicText: "رَبِّ اشْرَحْ لِي صَدْرِي وَيَسِّرْ لِي أَمْرِي وَاحْلُلْ عُقْدَةً مِنْ لِسَانِي يَفْقَهُوا قَوْلِي", transliteration: "Rabbişrah lî sadrî ve yessir lî emrî vahlul ukdeten min lisânî yefkahû kavlî", meaning: "Rabbim, göğsümü genişlet, işimi kolaylaştır, dilimden düğümü çöz ki sözümü anlasınlar.", purpose: "Hz. Musa'nın duası. Sınav, sunum ve güç konuşmalar öncesi okunur.", recommendedCount: 7, category: .hisnulMuslim, schedule: "Sınav öncesi", moodTags: ["sinav"]),
        RehberEntry(id: "hisnul_kaygı_giderme", title: "Kaygı ve Korku Giderme", arabicText: "حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ نِعْمَ الْمَوْلَى وَنِعْمَ النَّصِيرُ", transliteration: "Hasbünallâhü ve ni'mel vekîl. Ni'mel mevlâ ve ni'men-nasîr", meaning: "Allah bize yeter, O ne güzel vekildir. O ne iyi mevla ve ne iyi yardımcıdır.", purpose: "Hz. İbrahim ateşe atılırken bu duayı okudu. Her sıkıntıda güçlü bir zikirdir.", recommendedCount: 100, category: .hisnulMuslim, schedule: "Sıkıntı halinde", moodTags: ["huzursuz", "darda_kaldim"]),
        RehberEntry(id: "hisnul_gece_uyanis", title: "Gece Uyanışında Dua", arabicText: "لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ", transliteration: "Lâ ilâhe illallâhü vahdehû lâ şerîke leh lehül-mülkü ve lehül-hamdu ve Hüve alâ külli şey'in kadîr", meaning: "Allah'tan başka ilah yoktur; O birdir, ortağı yoktur. Mülk O'nundur, hamd O'nadır. Her şeye kadirdir.", purpose: "Gece uyanıldığında okunur ve ardından dua edilirse kabul olur. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Gece uyanışında"),
        RehberEntry(id: "hisnul_kızgınlık", title: "Öfke Halinde Dua", arabicText: "أَعُوذُ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ", transliteration: "Eûzü billâhi mineş-şeytânir-racîm", meaning: "Kovulmuş şeytandan Allah'a sığınırım.", purpose: "Öfke anında söylenir. Hz. Peygamber şiddetli öfke için bunu öğretti. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Öfke anında", moodTags: ["huzursuz"]),
        RehberEntry(id: "hisnul_istikhare", title: "İstihare Duası", arabicText: "اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ", transliteration: "Allâhümme innî estahîruke bi-ilmike ve estakdiruke bi-kudratike ve es'elüke min fadlikel-azîm", meaning: "Allah'ım, ilminle Senden hayırlısını istiyorum; kudretinle güç istiyorum ve büyük fazlından diliyorum.", purpose: "Önemli bir karar öncesinde 2 rekat namaz kılıp okunur. (Hadis: Buhârî)", recommendedCount: 1, category: .hisnulMuslim, schedule: "Karar öncesi"),
